// Dedupe items by URL (normalized: strip trailing slash, query params utm_*, fbclid, gclid)
// Also dedupe by title-similarity (lowercase, trim, first 80 chars)

function normalizeUrl(u) {
  try {
    const parsed = new URL(u);
    // Strip tracking params
    ['utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content', 'fbclid', 'gclid', 'mc_cid', 'mc_eid'].forEach(p => parsed.searchParams.delete(p));
    let clean = parsed.origin + parsed.pathname;
    if (parsed.search) clean += parsed.search;
    return clean.replace(/\/$/, '').toLowerCase();
  } catch (e) {
    return (u || '').toLowerCase().trim();
  }
}

const seenUrl = new Set();
const seenTitle = new Set();
const deduped = [];

for (const item of items) {
  const url = normalizeUrl(item.json.link);
  const titleKey = (item.json.title || '').toLowerCase().replace(/[^a-z0-9\s]/g, '').trim().substring(0, 80);

  if (seenUrl.has(url) || seenTitle.has(titleKey)) continue;
  seenUrl.add(url);
  seenTitle.add(titleKey);
  deduped.push(item);
}

return deduped;

const response = items[0].json;
let content;

if (response.message && response.message.content) {
  content = response.message.content;
} else if (response.choices && response.choices[0] && response.choices[0].message) {
  content = response.choices[0].message.content;
} else if (response.response) {
  content = response.response;
} else {
  content = JSON.stringify(response);
}

// Clean markdown
content = content.replace(/```json\n/g, '').replace(/```\n/g, '').replace(/```/g, '').trim();

// Auto-Repair 1: Fehlende Kommas zwischen Key-Value Paaren einfügen
// Beispiel: "summaryEn": "..."  "items" -> "summaryEn": "...", "items"
content = content.replace(/"\s*\n\s*"/g, '",\n"');
content = content.replace(/}(\s*)"items"/g, '},\n"items"');
content = content.replace(/"\s*"items"/g, '",\n"items"');

// Auto-Repair 2: Fehlende schließende Klammern ergänzen
const openBraces = (content.match(/\{/g) || []).length;
const closeBraces = (content.match(/\}/g) || []).length;
if (openBraces > closeBraces) {
  content = content + '}'.repeat(openBraces - closeBraces);
}

const openBrackets = (content.match(/\[/g) || []).length;
const closeBrackets = (content.match(/\]/g) || []).length;
if (openBrackets > closeBrackets) {
  content = content + ']'.repeat(openBrackets - closeBrackets) + '}'.repeat(openBraces - closeBraces);
}

// Parse JSON
let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      parsed = JSON.parse(jsonMatch[0]);
    } catch (e2) {
      throw new Error('Failed to parse LLM response as JSON. Content was: ' + content.substring(0, 500));
    }
  } else {
    throw new Error('No JSON found in LLM response. Content was: ' + content.substring(0, 500));
  }
}

// Validate structure
if (!parsed.summaryDe) {
  parsed.summaryDe = "Zusammenfassung der wichtigsten KI-News des Tages.";
}
if (!parsed.summaryEn) {
  parsed.summaryEn = "Summary of today's most important AI news.";
}
if (!parsed.items || !Array.isArray(parsed.items)) {
  throw new Error('Invalid structure: missing items array. Content: ' + content.substring(0, 500));
}

return [{ json: parsed }];

